class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLen = 0, countZeros = 0, countOnes = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '0') {
                countZeros++;
                countOnes = 0;
            } else {
                countOnes++;
                if (countZeros == countOnes) {
                    maxLen = Math.max(maxLen, 2 * countOnes);
                    countZeros = 0;
                    countOnes = 0;
                }
            }
        }
        return maxLen;
    }
}

